#include<bits/stdc++.h>
using namespace std;
string s;
int n,siz[105],dp[105][105];
bool check(int l,int r,int len)
{
    for(int i=l;i<=r;i++)
    {
        if(s[i]!=s[(i-l)%len+l]) return false;
    }
    return true;
}
int main()
{
    cin>>s;
    n=s.size();
    s=" "+s;
    for(int i=1;i<=9;i++) siz[i]=1;
    for(int i=10;i<100;i++) siz[i]=2;
    siz[100]=3;
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=n;i++) dp[i][i]=1;
    for(int len=2;len<=n;len++)
    {
        for(int l=1;l+len-1<=n;l++)
        {
            int r=l+len-1;
            for(int k=l;k<r;k++)
            {
                dp[l][r]=min(dp[l][r],dp[l][k]+dp[k+1][r]);
                int len2=k-l+1;
                if(len%len2) continue;
                if(check(l,r,len2)) dp[l][r]=min(dp[l][r],dp[l][k]+2+siz[len/len2]);
            }
        }
    }
    cout<<dp[1][n];
    return 0;
}
